import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge case: empty items ---
  it.todo("quote with empty item list -> premium 5 G (just the processing fee)");

  // --- Single main items, no modifiers, newcomer with no history but no first-insurance? ---
  // The first insurance surcharge applies to each item in a quote; loyalty/follow-up are policy-wide.
  // For a customer with 0 years and first-ever quote: only first-insurance surcharge applies per item.
  it.todo("quote: newcomer with a plain sword -> 100 + 10 first-insurance + 5 fee = 115 G");
  it.todo("quote: newcomer with a plain amulet -> 60 + 6 first-insurance + 5 fee = 71 G");
  it.todo("quote: newcomer with a plain staff -> 80 + 8 first-insurance + 5 fee = 93 G");
  it.todo("quote: newcomer with a plain potion -> 40 + 4 first-insurance + 5 fee = 49 G");

  // --- Components and the block-of-3 rule ---
  it.todo("quote: 2 runes -> 50 G base premium (newcomer: 50 + 5 first-insurance per rune? clarified below)");
  it.todo("quote: 3 runes -> 60 G base premium (block applies)");
  it.todo("quote: 4 runes -> 100 G base premium (no block, requires exactly 3)");
  it.todo("quote: 7 runes -> 175 G base premium");

  // --- "Alike" components: must be same type ---
  it.todo("quote: 2 runes + 1 moonstone -> 75 G base premium (no block: different types)");
  it.todo("quote: 3 runes + 3 moonstones -> 120 G base premium (two separate blocks)");

  // --- Modifier scope on multi-item policies ---
  it.todo("quote: cursed sword + plain amulet -> base 160, curse +50 = 210 G before further modifiers/fee");

  // --- Modifier thresholds ---
  it.todo("quote: customer with exactly 2 years -> loyalty discount applies");
  it.todo("quote: sword with exactly enchantment 5 -> high-enchantment surcharge applies");
  it.todo("quote: cursed sword with exactly enchantment 5 -> both surcharges apply");
  it.todo("quote: sword with enchantment 4 -> no high-enchantment surcharge");
  it.todo("quote: cursed sword with enchantment 4 -> only curse surcharge applies");

  // --- Rounding in MHPCO's favor ---
  it.todo("quote: premium that yields 197.5 G -> final premium 198 G (rounded up)");
  it.todo("payout that yields 350.5 G -> final payout 350 G (rounded down)");

  // --- Integration: newcomer with a cursed sword -> 165 G ---
  it.todo("integration: 0 years, cursed steel sword enchantment 3 -> 165 G");

  // --- Integration: long-standing customer's second contract -> 160 G ---
  it.todo("integration: 3 years, 2nd quote, cursed steel sword enchantment 7 -> 160 G");

  // --- Claim processing: standard ---
  it.todo("claim: regular sword enchantment 3, damage 500 G -> payout 400 G");
  it.todo("claim: rune insurance value 250 G, damage 200 G -> payout 100 G");

  // --- Claim: high-enchantment threshold ---
  it.todo("claim: steel sword enchantment 9, damage 1000 G -> payout 400 G (50% then deductible)");
  it.todo("claim: dragon-material sword enchantment 8, damage 1000 G -> payout 400 G (high-ench wins, then deductible)");

  // --- Claim: dragon material full reimbursement ---
  it.todo("claim: dragon-material sword enchantment 5, damage 800 G -> payout 700 G (full reimb, then deductible)");

  // --- Claim: dragon + high-ench together ---
  it.todo("claim: dragon-material sword enchantment 9, damage 1000 G -> payout 400 G (50% rule wins)");

  // --- Claim: deductible per damage event ---
  it.todo("claim: dragon attack damages sword (500) and amulet (300) -> payout 600 G");

  // --- Multiple items of the same type ---
  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; damage both -> two deductibles");
  it.todo("claim: more damages of a type than the policy covers -> non-zero exit, claim rejected");

  // --- Cap exhaustion ---
  it.todo("policy: sword + amulet -> insurance sum 1600 G, cap 3200 G");
  it.todo("policy: cursed sword premium 165 G -> cap 2000 G (based on unmodified insurance value)");
  it.todo("policy: sword + 3 runes (block) -> insurance sum 1750 G; block discount affects premium only");
  it.todo("policy: sword cap 2000 G; two successive 1500 G claims -> 1400/600 then 600/0");

  // --- Edge cases for input validation ---
  it.todo("quote with unknown item type -> non-zero exit, error to stderr, no results");
  it.todo("claim referencing item not in policy -> non-zero exit, error to stderr");
  it.todo("claim with negative damage amount -> non-zero exit, error to stderr");
});

