input.newString:
const PROCESSING_FEE = 5;

export const runScenario = (scenario: Scenario): ScenarioOutput => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      let policyBase = 0;
      for (const item of step.items) {
        if (item.type === "sword") {
          policyBase += 100 + 10; // base + first-insurance
        }
      }
      return { premium: policyBase + PROCESSING_FEE };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

