const COMPONENT_BLOCK_PREMIUM = 60;

const itemBasePremium = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const quoteItemsBasePremium = (items: Item[]): number => {
  if (
    items.length === COMPONENT_BLOCK_SIZE &&
    COMPONENT_TYPES.has(items[0].type) &&
    items.every((it) => it.type === items[0].type)
  ) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
};

