const itemBasePremium = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const isComponentBlock = (items: Item[]): boolean => {
  if (items.length !== COMPONENT_BLOCK_SIZE) return false;
  const firstType = items[0].type;
  return (
    COMPONENT_TYPES.has(firstType) &&
    items.every((item) => item.type === firstType)
  );
};

const quoteItemsBasePremium = (items: Item[]): number => {
  if (isComponentBlock(items)) return COMPONENT_BLOCK_PREMIUM;
  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
};

input.newString:
const itemBasePremium = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const groupBy = <T>(items: T[], key: (item: T) => string): Map<string, T[]> => {
  const groups = new Map<string, T[]>();
  for (const item of items) {
    const k = key(item);
    const existing = groups.get(k);
    if (existing) existing.push(item); else groups.set(k, [item]);
  }
  return groups;
};

const groupBasePremium = (group: Item[]): number => {
  if (group.length === COMPONENT_BLOCK_SIZE && isComponent(group[0])) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return group.reduce((sum, item) => sum + itemBasePremium(item), 0);
};

const quoteItemsBasePremium = (items: Item[]): number => {
  const groups = groupBy(items, (item) => item.type);
  let total = 0;
  for (const group of groups.values()) {
    total += groupBasePremium(group);
  }
  return total;
};

