const loyaltyDiscount = (customer: Customer, base: number): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;

const runQuoteStep = (step: QuoteStep, customer: Customer): QuoteResult => {
  const base = quoteItemsBasePremium(step.items);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
  const surcharges = sumItemSurcharges(step.items);
  const discount = loyaltyDiscount(customer, base);
  return {
    premium: roundPremium(base + surcharges + firstInsuranceSurcharge - discount + PROCESSING_FEE),
  };
};

const runStep = (step: Step, customer: Customer): StepResult => {
  if (step.op === "quote") return runQuoteStep(step, customer);
  return { payout: 0, remainingCap: 0 };
};

export const runScenario = (scenario: Scenario): ScenarioOutput => {
  return { results: scenario.steps.map((step) => runStep(step, scenario.customer)) };
};

