export const runScenario = (scenario: Scenario): ScenarioOutput => {
  let quoteCount = 0;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const ctx: QuoteContext = { customer: scenario.customer, isFollowUp: quoteCount > 0 };
