const damagePayoutBeforeCap = (damage: Damage): number => {
  const reimbursable = damage.amount;
  return Math.max(0, reimbursable - DEDUCTIBLE);
};

const runClaimStep = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
  const policy = policies.get(step.policy);
  if (!policy) throw new Error(`policy ${step.policy} not found`);
  const requested = step.incident.damages.reduce(
    (sum, d) => sum + damagePayoutBeforeCap(d),
    0,
  );
  const payout = Math.min(requested, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

