const countByType = (items: { type?: string; itemType?: string }[], key: "type" | "itemType"): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    const k = item[key] as string;
    counts.set(k, (counts.get(k) ?? 0) + 1);
  }
  return counts;
};

const assertDamagesCoveredByPolicy = (damages: Damage[], policy: Policy): void => {
  const damageCounts = countByType(damages, "itemType");
  const itemCounts = countByType(policy.items, "type");
  for (const [type, dCount] of damageCounts) {
    const iCount = itemCounts.get(type) ?? 0;
    if (dCount > iCount) {
      throw new Error(`too many damages of type ${type} for policy`);
    }
  }
};

