```typescript
const findPolicy = (policies, id): Policy => {
  const policy = policies.get(id);
  if (!policy) throw new Error(`policy ${id} not found`);
  return policy;
};

const validateClaim = (damages, policy): void => {
  damages.forEach(assertNonNegativeDamage);
  assertDamagesCoveredByPolicy(damages, policy);
};

const requestedPayout = (damages, policy): number =>
  damages.reduce(
